const targetDirectory = pm.environment.get("file_dir"); 

async function getAllFilePaths() {
    try {
        // 调用外部Python程序获取文件列表[5](@ref)
        const result = await pm.executeAsync("get_files.py", [targetDirectory]);
    
        
        // 解析返回的JSON数据
        const data = JSON.parse(result);
        
        if (data.success) {
            const fileList = data.files;
            const fileCount = data.file_count;
           
            
            // 将完整文件列表存储到环境变量
            pm.variables.set("all_file_paths", JSON.stringify(fileList));
    
            
            // 设置当前文件索引（用于循环）
            var current_index=pm.variables.get("current_file_index")
          
            if (!current_index){
                current_index = "0";
                pm.variables.set("current_file_index", current_index);
        
            
            }
           
            
            // 如果存在文件，设置第一个文件路径为当前文件
            if (fileCount > 0  ) {
                pm.variables.set("current_file_path", fileList[current_index]);
                pm.variables.set("current_file_name", fileList[current_index].split(/[\\/]/).pop());
            }
            
            console.log(`成功获取 ${fileCount} 个文件路径`);
            console.log("目录:", data.directory);
            
            return fileList;
        } else {
            console.error("获取文件列表失败:", data.error);
            return [];
        }
    } catch (error) {
        console.error("执行外部程序时出错:", error.message);
        return [];
    }
}

// 执行文件获取
getAllFilePaths();

