        // 在后置脚本中更新文件索引，准备处理下一个文件
function prepareNextFile() {
    try {
        const currentIndex = parseInt(pm.variables.get("current_file_index") || "0");
        const totalFiles = parseInt(pm.variables.get("total_file_count") || "0");
        
        if (totalFiles === 0) return;
        
        // 使用之前设置的next_file_index，或递增当前索引
        let nextIndex = parseInt(pm.variables.get("next_file_index") || (currentIndex + 1).toString());
        
        // 检查是否完成循环
        if (nextIndex >= totalFiles) {
            console.log("🎉 所有文件处理完成!");
            pm.variables.set("processing_complete", "true");
            // 可以选择重置索引以重新开始循环
            // nextIndex = 0;
        } else {
            pm.variables.set("current_file_index", nextIndex.toString());
            
            // 获取下一个文件路径
            const allFiles = JSON.parse(pm.variables.get("all_file_paths") || "[]");
            if (allFiles.length > nextIndex) {
                const nextFilePath = allFiles[nextIndex];
                pm.variables.set("next_file_path", nextFilePath);
                pm.variables.set("next_file_name", nextFilePath.split(/[\\/]/).pop());
            }
            
            console.log(`下一个待处理文件索引: ${nextIndex}`);
        }
        
    } catch (error) {
        console.error("更新文件索引时出错:", error);
    }
}

// 执行后置处理
prepareNextFile();

